SELECT AVG(deaths.age) AS average_age
FROM deaths
WHERE deaths.county_of_residence = 'specific county';

SELECT COUNT(*)
FROM deaths
WHERE county_of_residence = 'Your County Name';

SELECT DISTINCT TRIM(event_type) 
FROM events 
WHERE event_type IS NOT NULL AND event_type <> '';

SELECT death_location
FROM deaths
ORDER BY death_location ASC;

SELECT death_id, event_id, year_of_death, residence_or_place_of_death, age
FROM deaths
WHERE age != 'Less than 1 year';

SELECT event_id, event_type, event_category, event_severity, event_timestamp
FROM events
WHERE event_id > 0;

SELECT age, COUNT(*) as total_deaths
FROM deaths
GROUP BY age;
